class Cart {
    constructor() {
        this.$cart = $('#cartIcon')
        this.$badge = this.$cart.find('.badge');
        this.$items = this.$cart.parents('.cartContainer').find('.items');

        this.init();
    }

    init() {
        this.$cart.parents('.cartContainer').mouseenter((e) => {
            if (this.$items.find('.row').length > 0) {
                this.$cart.attr('style', '');
                this.$cart.parents('.cartContainer').find('.content').stop().slideDown(100);
            }
        }).mouseleave((e) => {
                this.$cart.parents('.cartContainer').find('.content').slideUp(100);
        });
        this.getItems();
    }

    refreshCart(flash = true) {
        $.ajax({
            url: basePath + '/default/cart/get-count',
            success: (data) => {
                if (flash) {
                    this.flashCart();
                }
                if (data > 0) {
                    this.$badge.text(data);
                    this.$badge.removeClass('empty');
                } else {
                    this.$badge.text(0);
                    this.$badge.addClass('empty');
                }
            }
        })
        this.getItems();
    }

    flashCart() {
        this.$badge.addClass('blink');
        setTimeout(() => {
            this.$badge.removeClass('blink');
         }, 500);
    }

    getItems() {
        $.ajax({
            url: basePath + '/default/cart/get-items',
            success: (data) => {
                this.$items.html('');
                if (!data.startsWith("[") && !data.startsWith('{')) {
                    return;
                }
                var new_data = JSON.parse(data);
                var total = 0;
                var currency = '€';
                for (var i = 0; i<new_data.length; i++) {
                    var html = `<div class="row">
                    <div class="col thumb">`;
                    if (new_data[i].Image != null) {
                        html += '<img src="' + basePath + '/files/images/remante/800/' + new_data[i].Image + '">';
                    } else {
                        html += '<img src="' + basePath + '/core/img/cdb-icons/package.svg">';
                    }
                    html += `</div>
                    <div class="col product">
                    <a href="${basePath}/default/product/index?search=${new_data[i].Product_ID}">${new_data[i].Product}</a>
                    </div>
                    <div class="col-4 info">
                        <span class="quantity">${new_data[i].Quantity}x</span>
                        <span class="price">${Helpers.formatPrice(new_data[i].Quantity * new_data[i].Price)} ${new_data[i].Currency}</span>
                    </div>
                    </div>`;
                    total += (new_data[i].Quantity * new_data[i].Price);
                    currency = new_data[i].Currency
                    this.$items.append(html);
                }

                this.$cart.parents('.cartContainer').find('.total span').text(Helpers.formatPrice(total) + ` ${currency}`);
            }
        });
    }
}